$base = "D:\ClaudeCode\ngl-frac-spread"

Write-Host "Adding contract comparison panel...`n" -ForegroundColor Cyan

$p = Join-Path $base "src\App.jsx"; $d = Split-Path $p
if (!(Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
[System.IO.File]::WriteAllBytes($p, [System.Convert]::FromBase64String(""))
Write-Host "  updated: src\App.jsx" -ForegroundColor Green

$p = Join-Path $base "src\components\ContractComparison.jsx"; $d = Split-Path $p
if (!(Test-Path $d)) { New-Item -ItemType Directory -Path $d -Force | Out-Null }
[System.IO.File]::WriteAllBytes($p, [System.Convert]::FromBase64String(""))
Write-Host "  updated: src\components\ContractComparison.jsx" -ForegroundColor Green

Write-Host "\nDone! Browser should hot-reload." -ForegroundColor Green
